mapper.select:
SELECT b.BOARD_ID, b.BOARD_TITLE, b.BOARD_HIT, b.BOARD_DATE, b.MEMBER_ID, m.MEMBER_LOGINID FROM BOARD b JOIN MEMBER m ON b.MEMBER_ID = m.MEMBER_ID
(b.BOARD_TITLE LIKE CONCAT('%', #{keyword}, '%') OR m.MEMBER_LOGINID LIKE CONCAT('%', #{keyword}, '%'))
ORDER BY b.BOARD_ID DESC LIMIT #{size} OFFSET #{offset}

mapper.update:
UPDATE BOARD
   SET BOARD_HIT = BOARD_HIT + 1
WHERE BOARD_ID = #{boardId}

UPDATE BOARD
   SET BOARD_TITLE = #{boardTitle},
      BOARD_CONTENT = #{boardContent}
   WHERE BOARD_ID = #{boardId}
